return useMemo(() => {
    return new Set([focusedKey, dropTargetKey].filter(k => k != null));
  }, [focusedKey, dropTargetKey]);

if (state.collection.size === 0 && props.renderEmptyState) {
  emptyState = (
    <div role="menuitem" style={{display: 'contents'}}>
      {props.renderEmptyState()}
    </div>
  );
}

let layout = useMemo(
  () => (typeof layoutProp === 'function' ? new layoutProp() : layoutProp),
  [layoutProp]
);

useEffect(() => {
    document.addEventListener('keyup', onKeyUpCapture, true);
    return () => {
      document.removeEventListener('keyup', onKeyUpCapture, true);
    };
  }, []);

let ariaLabel = useMemo(
  () => new Intl.DisplayNames(locale, {type: 'dateTimeField'}).of('month')!,
  [locale]
);

let ariaLabel = useMemo(
  () => new Intl.DisplayNames(locale, {type: 'dateTimeField'}).of('year')!,
  [locale]
);

useEvent(windowRef, 'pointerdown', e => {
  isVirtualClick.current = e.width === 0 && e.height === 0;
});

const commitBehaviorMapping = {
  clear: () => state.clearSelection(),
  reset: () => state.setAnchorDate(null),
  select: () => state.commitSelection()
};

for (let i = 0; i < parts.length; i++) {
  if (i < separatorIndex) {
    startValue += parts[i].value;
  } else if (i > separatorIndex) {
    endValue += parts[i].value;
  }
}

let [document] = useState(
  () => new Document<T, C>(createCollection?.() || (new BaseCollection() as C))
);

let Result = (forwardRef as forwardRefType)((props: P, ref: ForwardedRef<E>) => {
  let children = useChildren(props);
  return (
    useSSRCollectionNode(CollectionNodeClass, props, ref, null, children, node => (
      <Component node={node} />
    )) ?? <></>
  );
});

if (
  this._minInvalidChildIndex == null ||
  !this._minInvalidChildIndex.isConnected ||
  child.index < this._minInvalidChildIndex.index
) {
  this._minInvalidChildIndex = child;
  this.ownerDocument.markDirty(this);
}

let childrenString = useMemo(
  () =>
    process.env.NODE_ENV !== 'production' && typeof children === 'function'
      ? children.toString()
      : undefined,
  [children]
);

let {focusProps: xInputFocusProps} = useFocus({
  onFocus: () => {
    setFocusedInput('x');
  }
});

let {focusProps: yInputFocusProps} = useFocus({
  onFocus: () => {
    setFocusedInput('y');
  }
});

let {visuallyHiddenProps} = useVisuallyHidden({
  style: {
    opacity: '0.0001',
    width: '100%',
    height: '100%',
    pointerEvents: 'none'
  }
});

useEffect(() => {
    return () => {
      if (raf.current) {
        cancelAnimationFrame(raf.current);
      }
    };
  }, []);

useEffect(() => {
    let cb = () => setSession(dragSession);
    subscriptions.add(cb);
    return () => {
      subscriptions.delete(cb);
    };
  }, []);

if (e.key === 'Enter') {
  if (e.altKey || nodeContains(this.getCurrentActivateButton(), getEventTarget(e) as Node)) {
    this.activate(this.currentDropTarget, this.currentDropItem);
  } else {
    this.drop();
  }
}

if (
  (e.type === 'focusin' || e.type === 'focusout') &&
  (eventTarget === this.dragTarget?.element || eventTarget === this.getCurrentActivateButton())
) {
  return;
}

requestAnimationFrame(() => {
  if (dragSession) {
    dragSession.setup();
    if (getDragModality() === 'keyboard') {
      dragSession.next();
    }
  }
});

let onPress = (e: PressEvent) => {
  if (e.pointerType !== 'keyboard' && e.pointerType !== 'virtual') {
    return;
  }

  startDragging(e.target as HTMLElement);
};

let onKeyboardDrop = useEffectEvent((e: DropEvent) => {
  if (typeof options.onDrop === 'function') {
    options.onDrop(e);
  }
});

let getText = (key: Key | null) => {
  if (key == null) {
    return '';
  } else {
    return collection.getTextValue?.(key) ?? collection.getItem(key)?.textValue ?? '';
  }
};

useEffect(() => {
    return () => {
      if (droppingState.current) {
        clearTimeout(droppingState.current.timeout);
      }
    };
  }, []);

useFocusVisibleListener(
  isFocusVisible => {
    state.current.isFocusVisible = isFocusVisible;
    updateState();
  },
  [isTextInput, isFocused],
  {enabled: isFocused, isTextInput}
);

if (from !== to) {
  if (from) {
    dispatchVirtualBlur(from, to);
  }
  if (to) {
    dispatchVirtualFocus(to, from);
  }
}

while (itemRect && itemRect.y > pageY && key != null) {
  key = this.getKeyAbove(key) ?? null;
  if (key == null) {
    break;
  }
  itemRect = this.layoutDelegate.getItemRect(key);
}

let navDisabledHandlers = useMemo(
  () => ({
    onBlur: collectionProps.onBlur,
    onFocus
  }),
  [onFocus, collectionProps.onBlur]
);

return {
  checkboxProps: {
    ...checkboxProps,
    'aria-labelledby': `${checkboxProps.id} ${getRowId(state, key)}`
  }
};
